/**
 * 统计英语作文中的单词数量
 * 适配新输入结构：作文文本位于 body.content 中
 */

// 1. 获取所有输入项
const items = $input.all() || [];

// 2. 遍历所有输入项
items.forEach((item) => {
    // 3. 确保item和json存在，防止数据结构异常导致报错
    if (!item) item = { json: {} };
    if (!item.json) item.json = {};

    // 4. 获取作文文本【核心修改：从body.content取数，适配新结构】
    const essay = item.json.body?.content;

    // 5. 统计单词数（原有逻辑不变，鲁棒性保留）
    let wordCount = 0;
    if (essay && typeof essay === 'string') {
        // 匹配所有英文字母组成的单词，兼容大小写
        const wordRegex = /[a-zA-Z]+/g;
        const words = essay.match(wordRegex);
        wordCount = words ? words.length : 0;
    }

    // 6. 为原始数据添加essay_num字段，存储单词统计数
    item.json.essay_num = wordCount;

    // 7. 打印日志，方便调试查看统计结果
    console.log(`作文单词数: ${wordCount}`);
});

// 8. 返回处理后的数据，保持原有输出格式
return items;

// n8n Code节点专用 | 适配Markdown包裹的JSON格式 | 完整保留所有字段 | 仅校正格式
try {
    // 1. 获取上游原始的content数据（带```json/```和换行）
    const contentWithMarkdown = $input.first().json.content || '';

    // 2. 核心步骤：剥离Markdown的JSON包裹标记 + 清理多余换行/空格，提取纯JSON字符串
    const pureJsonStr = contentWithMarkdown
        .replace(/^```json\s*/, '') // 去掉开头的```json和后续空白
        .replace(/\s*```$/, '')     // 去掉结尾的```和前面的空白
        .replace(/\n+/g, ' ')      // 清理所有多余换行符
        .trim();                   // 清理首尾空格

    // 3. 解析纯JSON字符串为对象（此时是合法的JSON了）
    const rawRoot = JSON.parse(pureJsonStr);

    // 4. 完整复制原始data的所有字段（包括comment/score/error_set等，一个不丢）
    const finalData = { ...(rawRoot.data || {}) };

    // 5. 仅对核心字段做【类型标准化校正】，不修改任何原始值
    finalData.score = Number(finalData.score) || 0; // score强制数字
    finalData.highlight = Array.isArray(finalData.highlight) ? finalData.highlight : []; // 强制数组
    finalData.error_set = Array.isArray(finalData.error_set) 
        ? finalData.error_set.map(err => ({
            ...err, // 完整保留错误项所有字段
            offset: Number(err.offset) || 0, // 仅校正为数字
            length: Number(err.length) || 0  // 仅校正为数字
        }))
        : [];

    // 6. n8n标准输出：组装结果并返回
    return [{ json: { data: finalData } }];

} catch (error) {
    // 异常兜底：打印错误日志（方便排查）+ 返回格式合法的空结构
    console.error('【JSON处理失败详情】', error.message);
    return [{
        json: {
            data: {
                comment: '',
                score: 0,
                highlight: [],
                error_set: []
            }
        }
    }];
}

// n8n Code 节点 JS 脚本，提取作文文本的字符索引信息
// 核心入参：$input.first().json.content （作文内容）
const inputData = $input.first().json;
// 拿到作文内容，做非空校验
const essayContent = inputData.content || "";

// 初始化返回结果
const result = {
  // 保留原始作文内容，方便模型对照
  originalEssay: essayContent,
  // 字符-索引结构化映射（数组），每个元素含index(索引)、char(字符)，精准无遗漏
  charIndexMap: [],
  // 极简索引字符串（0:H,1:e,2: ,3:w...），方便模型快速读取
  formattedIndexStr: ""
};

// 若作文内容为空，直接返回提示
if (!essayContent) {
  result.error = "提示：未获取到作文内容，请检查入参content是否存在";
  return result;
}

// 遍历作文每个字符，生成索引映射（索引从0开始，包含空格/标点/换行）
for (let i = 0; i < essayContent.length; i++) {
  const char = essayContent[i];
  // 填充结构化映射数组
  result.charIndexMap.push({
    index: i,
    char: char // 保留原始字符，包括空格、逗号、句号、换行等
  });
  // 拼接极简索引字符串（适配模型快速读取格式）
  result.formattedIndexStr += `${i}:${char.replace(/,/g, '，')},`;
}

// 去除极简字符串末尾多余的逗号，保证格式整洁
result.formattedIndexStr = result.formattedIndexStr.slice(0, -1);

// 核心返回：所有索引信息+原作文
return result;
